    Договор = Неопределено;
    МаксДатаНачала = Дата(1, 1, 1);

    Запрос = Новый Запрос;
    Запрос.Текст = "
        ВЫБРАТЬ
            Договоры.Ссылка,
            Договоры.ДатаНачала,
            Договоры.ДатаОкончания
        ИЗ
            Справочник.Договоры КАК Договоры
        ГДЕ
            Договоры.Владелец = &Контрагент
            И Договоры.ДатаНачала <= &ДатаСреза
            И (Договоры.ДатаОкончания >= &ДатаСреза ИЛИ Договоры.ДатаОкончания = ДАТАВРЕМЯ(1, 1, 1, 0, 0, 0))
    ";

    Запрос.УстановитьПараметр("Контрагент", Контрагент);
    Запрос.УстановитьПараметр("ДатаСреза", ДатаСреза);

    Результат = Запрос.Выполнить();
    Выборка = Результат.Выбрать();

    Пока Выборка.Следующий() Цикл
        Если Выборка.ДатаНачала > МаксДатаНачала Тогда
            МаксДатаНачала = Выборка.ДатаНачала;
            Договор = Выборка.Ссылка;
        КонецЕсли;
    КонецЦикла;

    Возврат Договор;

КонецФункции
